      require 'uri'
      require 'json'
      base_url = ENV.fetch('SUT_URL', 'http://127.0.0.1:8000')
      uri = URI.parse("#{base_url}/fixtures/special_characters_encoding/form/")
      http = Net::HTTP.new(uri.host, uri.port)
      http.use_ssl = uri.scheme == 'https'
      _headers = {
      'Content-Type' => 'application/x-www-form-urlencoded',
    }.dup
      _headers['Content-Type'] ||= 'application/json'
      _req = Net::HTTP::Post.new(uri.request_uri, _headers)
      _req.body = 'name=John+Doe&description=Test+%26+Development'
      response = http.request(_req)
      expect(response.code.to_i).to eq(200)
      _body = response.body && !response.body.empty? ? JSON.parse(response.body) : nil
      expect(_body).to eq({ 'description' => 'Test & Development', 'name' => 'John Doe' })
    end
  end

  describe 'string_max_length_validation_fail_2' do
    it 'Tests form field with max_length constraint failure.' do
      require 'net/http'
      require 'uri'
      require 'json'
      base_url = ENV.fetch('SUT_URL', 'http://127.0.0.1:8000')
      uri = URI.parse("#{base_url}/fixtures/string_max_length_validation_fail_2/form/validated")
      http = Net::HTTP.new(uri.host, uri.port)
      http.use_ssl = uri.scheme == 'https'
      _headers = {
      'Content-Type' => 'application/x-www-form-urlencoded',
    }.dup
      _headers['Content-Type'] ||= 'application/json'
      _req = Net::HTTP::Post.new(uri.request_uri, _headers)
      _req.body = 'username=this_is_a_very_long_username_that_exceeds_limit'
      response = http.request(_req)
      expect(response.code.to_i).to eq(422)
      _body = response.body && !response.body.empty? ? JSON.parse(response.body) : nil
      expect(_body).to eq({ 'detail' => '1 validation error in request', 'errors' => [{ 'ctx' => { 'max_length' => 20 }, 'input' => 'this_is_a_very_long_username_that_exceeds_limit', 'loc' => ['body', 'username'], 'msg' => 'String should have at most 20 characters', 'type' => 'string_too_long' }], 'status' => 422, 'title' => 'Request Validation Failed', 'type' => 'https://spikard.dev/errors/validation-error' })
      _body = JSON.parse(response.body)
      _errors = _body['errors'] || []
      expect(_errors.any? { |e| e['loc'] == ['body', 'username'] && e['msg'].include?('String should have at most 20 characters') }).to be true
    end
  end

